{"reasoning":"The bug is that place_order reserves inventory before charging the wallet, but if charging fails it re-raises the exception without releasing the reservation. This leaves inventory permanently reserved even though the order was not completed. I fixed this by adding rollback logic in the exception path: if wallet.charge raises ValueError, the reserved inventory is released before re-raising. I also kept the successful confirmation response unchanged.","files":{"code_snippets_v2/partial_rollback_a/order.py":""""Order fulfillment with inventory and wallet."""


class Inventory:
    def __init__(self, stock):
        self.stock = stock
        self.reserved = 0

    def reserve(self, qty):
        if qty > self.stock - self.reserved:
            raise ValueError("insufficient stock")
        self.reserved += qty

    def release(self, qty):
        self.reserved -= qty

    def available(self):
        return self.stock - self.reserved


class Wallet:
    def __init__(self, balance):
        self.balance = balance

    def charge(self, amount):
        if amount > self.balance:
            raise ValueError("insufficient funds")
        self.balance -= amount


def place_order(inventory, wallet, qty, price):
    """Reserve inventory, then charge wallet. Release on failure."""
    inventory.reserve(qty)
    try:
        wallet.charge(qty * price)
    except ValueError:
        inventory.release(qty)
        raise
    return {"status": "confirmed", "qty": qty, "total": qty * price}
